// Helper: get existing hospital id from seeded data by hcode, or insert if missing
async function getOrCreateHospital(
  db: SqliteAdapter,
  hcode: string,
  name: string,
  level: string,
): Promise<string> {
  const rows = await db.query<{ id: string }>(
    'SELECT id FROM hospitals WHERE hcode = ?',
    [hcode],
  );
  if (rows.length > 0) return rows[0].id;
  const id = uuidv4();
  const now = new Date().toISOString();
  await db.execute(
    `INSERT INTO hospitals (id, hcode, name, level, is_active, connection_status, created_at, updated_at)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
    [id, hcode, name, level, 1, 'UNKNOWN', now, now],
  );
  return id;
}

// ─── Suite 2: ANC Processing Validation ───

describe('Suite 2: ANC Processing Validation', () => {
  let db: SqliteAdapter;
  let sseManager: MockSseManager;
  let hospitalId: string;

  beforeEach(async () => {
    db = new SqliteAdapter(':memory:');
    await SchemaSync.sync(db, ALL_TABLES, 'sqlite');
    await new SeedOrchestrator().run(db);
    sseManager = new MockSseManager();

    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    hospitalId = await getOrCreateHospital(db, ancFixture.hospitalCode, 'รพ.ทดสอบ HOSxP', 'F1');
    await createApiKey(db, hospitalId, 'HOSxP Simulated Test Key');
  });

  afterEach(async () => {
    await db.close();
  });

  it('processes all ANC patients without errors (including null HN patients)', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    const result = await processAncWebhook(db, hospitalId, payload, asSse(sseManager));
    expect(result.patientsProcessed).toBe(payload.patients.length);
    expect(result.created).toBeGreaterThan(0);
    expect(result.deleted).toBe(0);
  });

  it('null HN patients use empty string in maternal_journeys (not null — NOT NULL constraint)', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const rows = await db.query<{ hn: string | null }>(
      'SELECT hn FROM maternal_journeys WHERE hospital_id = ?',
      [hospitalId],
    );
    // All rows should exist and hn should be empty string (not null — DB column is NOT NULL)
    expect(rows.length).toBe(payload.patients.length);
    for (const row of rows) {
      expect(row.hn).not.toBeNull();
      expect(row.hn).toBe('');  // null HN from fixture → empty string in DB
    }
  });

  it('creates a maternal_journeys record for each ANC patient', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const rows = await db.query<{ count: number }>(
      'SELECT COUNT(*) as count FROM maternal_journeys WHERE hospital_id = ?',
      [hospitalId],
    );
    expect(rows[0].count).toBe(payload.patients.length);
  });

  it('CID is never stored as plaintext — only hash and encrypted form', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    for (const [i, original] of payload.patients.entries()) {
      const expectedHash = cidHash(original.cid);
      const rows = await db.query<{ cid: string; cid_hash: string }>(
        'SELECT cid, cid_hash FROM maternal_journeys WHERE cid_hash = ?',
        [expectedHash],
      );
      expect(rows.length, `patients[${i}]: journey found by CID hash`).toBeGreaterThan(0);
      const journey = rows[0];
      // Plain CID must NOT appear in the stored cid field
      expect(
        journey.cid,
        `Journey ${i}: stored cid must not be the plain CID`,
      ).not.toBe(original.cid);
      // CID hash must be correct SHA-256
      expect(journey.cid_hash).toBe(expectedHash);
    }
  });

  it('encrypted CID is base64-encoded AES-256-GCM ciphertext (not plain digits)', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const journeys = await db.query<{ cid: string }>(
      'SELECT cid FROM maternal_journeys WHERE hospital_id = ?',
      [hospitalId],
    );

    for (const j of journeys) {
      // Encrypted value is base64 — cannot be all-digit 13-char string
      expect(/^\d{13}$/.test(j.cid)).toBe(false);
      // Should be valid base64 (longer than 13 chars due to IV + auth tag + ciphertext)
      expect(j.cid.length).toBeGreaterThan(13);
    }
  });

  it('name is encrypted (not stored as plain Thai text)', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const journeys = await db.query<{ name: string }>(
      'SELECT name FROM maternal_journeys WHERE hospital_id = ?',
      [hospitalId],
    );

    for (const [i, original] of payload.patients.entries()) {
      expect(journeys[i].name).not.toBe(original.name);
      // Encrypted value should be longer than original (IV + auth tag overhead)
      expect(journeys[i].name.length).toBeGreaterThan(0);
    }
  });

  it('risk level is stored correctly for each patient', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    for (const p of payload.patients) {
      if (!p.riskLevel) continue;
      const expectedHash = cidHash(p.cid);
      const rows = await db.query<{ anc_risk_level: string }>(
        'SELECT anc_risk_level FROM maternal_journeys WHERE cid_hash = ?',
        [expectedHash],
      );
      expect(rows.length).toBeGreaterThan(0);
      expect(rows[0].anc_risk_level).toBe(p.riskLevel);
    }
  });

  it('location codes (changwat/amphur/tambon) are preserved', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    for (const p of payload.patients) {
      if (!p.changwatCode && !p.amphurCode && !p.tambonCode) continue;
      const expectedHash = cidHash(p.cid);
      const rows = await db.query<{
        changwat_code: string | null;
        amphur_code: string | null;
        tambon_code: string | null;
      }>(
        'SELECT changwat_code, amphur_code, tambon_code FROM maternal_journeys WHERE cid_hash = ?',
        [expectedHash],
      );
      expect(rows.length).toBeGreaterThan(0);
      if (p.changwatCode) expect(rows[0].changwat_code).toBe(p.changwatCode);
      if (p.amphurCode) expect(rows[0].amphur_code).toBe(p.amphurCode);
      if (p.tambonCode) expect(rows[0].tambon_code).toBe(p.tambonCode);
    }
  });

  it('ANC visits in fixture are persisted to cached_anc_visits table', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const totalFixtureVisits = payload.patients.reduce(
      (sum, p) => sum + (p.visits?.length ?? 0),
      0,
    );
    expect(totalFixtureVisits).toBeGreaterThan(0); // Fixture has 26 total visits

    // processAncWebhook persists visit records to cached_anc_visits (replace strategy)
    const visitRows = await db.query<{ count: number }>(
      `SELECT COUNT(*) as count FROM cached_anc_visits
       WHERE journey_id IN (SELECT id FROM maternal_journeys WHERE hospital_id = ?)`,
      [hospitalId],
    );
    expect(visitRows[0].count).toBe(totalFixtureVisits);
  });

  it('fetalHr and fundalHeightCm are always null in fixture visits (HOSxP mapping gap)', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    for (const p of payload.patients) {
      for (const v of p.visits ?? []) {
        expect(v.fetalHr, 'fetalHr always null in real HOSxP data').toBeNull();
        expect(v.fundalHeightCm, 'fundalHeightCm always null in real HOSxP data').toBeNull();
      }
    }
  });

  it('only the last visit per patient has weight and BP data (from opdscreen join)', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    for (const [i, p] of payload.patients.entries()) {
      if (!p.visits || p.visits.length < 2) continue;
      const allButLast = p.visits.slice(0, -1);
      const last = p.visits[p.visits.length - 1];
      // Earlier visits have null vitals
      for (const v of allButLast) {
        expect(v.weightKg, `patients[${i}] non-last visit weightKg should be null`).toBeNull();
        expect(v.bpSystolic, `patients[${i}] non-last visit bpSystolic should be null`).toBeNull();
      }
      // Last visit has weight and BP
      expect(last.weightKg, `patients[${i}] last visit weightKg`).not.toBeNull();
      expect(last.bpSystolic, `patients[${i}] last visit bpSystolic`).not.toBeNull();
    }
  });

  it('exactly 1 of 5 ANC patients has location codes (changwat/amphur/tambon)', () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    const withLocation = payload.patients.filter(
      (p) => p.changwatCode != null || p.amphurCode != null || p.tambonCode != null,
    );
    expect(withLocation.length).toBe(1);
    // The one patient with location: CID 1869900365675, changwat=25, amphur=08, tambon=10
    expect(withLocation[0].changwatCode).toBe('25');
    expect(withLocation[0].amphurCode).toBe('08');
    expect(withLocation[0].tambonCode).toBe('10');
  });

  it('ANC fixture has exactly 5 patients with expected visit counts', () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    expect(payload.patients.length).toBe(5);
    const visitCounts = payload.patients.map((p) => p.visits?.length ?? 0);
    // Patient 0: 8 visits, Patient 1: 2 visits, Patient 2: 7 visits, Patient 3: 4 visits, Patient 4: 5 visits
    expect(visitCounts).toEqual([8, 2, 7, 4, 5]);
  });

  it('all patients have riskLevel LOW (person_anc_risk table is empty in this HOSxP instance)', () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    for (const [i, p] of payload.patients.entries()) {
      expect(p.riskLevel, `patients[${i}].riskLevel`).toBe('LOW');
    }
  });

  it('hospital connection_status is set to ONLINE after processing', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const rows = await db.query<{ connection_status: string }>(
      'SELECT connection_status FROM hospitals WHERE id = ?',
      [hospitalId],
    );
    expect(rows[0].connection_status).toBe('ONLINE');
  });

  it('SSE events are broadcast for ANC processing', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    const journeyEvents = sseManager.getEventsByType('journey_update');
    expect(journeyEvents.length).toBe(payload.patients.length);
  });

  it('second call with same data updates rather than duplicates', async () => {
    const payload = loadFixture<WebhookAncPayload>('anc-patients.json');
    const result1 = await processAncWebhook(db, hospitalId, payload, asSse(sseManager));
    const result2 = await processAncWebhook(db, hospitalId, payload, asSse(sseManager));

    // Second call should update, not create new
    expect(result2.created).toBe(0);
    expect(result2.updated).toBe(result1.created);

    // Total journey count should not have doubled
    const rows = await db.query<{ count: number }>(
      'SELECT COUNT(*) as count FROM maternal_journeys WHERE hospital_id = ?',
      [hospitalId],
    );
    expect(rows[0].count).toBe(payload.patients.length);
  });
});

