describe('Suite 3: Labor Processing Validation', () => {
  let db: SqliteAdapter;
  let sseManager: MockSseManager;
  let hospitalId: string;

  beforeEach(async () => {
    db = new SqliteAdapter(':memory:');
    await SchemaSync.sync(db, ALL_TABLES, 'sqlite');
    await new SeedOrchestrator().run(db);
    sseManager = new MockSseManager();

    const laborFixture = loadFixture<WebhookPayload>('labor-patients.json');
    hospitalId = await getOrCreateHospital(db, laborFixture.hospitalCode, 'รพ.ทดสอบ HOSxP Labor', 'F1');
    await createApiKey(db, hospitalId, 'HOSxP Labor Test Key');
  });

  afterEach(async () => {
    await db.close();
  });

  it('processes all labor patients without errors', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    const result = await processWebhookPayload(db, hospitalId, payload, asSse(sseManager));
    expect(result.patientsProcessed).toBe(payload.patients.length);
    expect(result.deleted).toBe(0);
  });

  it('creates cached_patients records for each labor patient', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    await processWebhookPayload(db, hospitalId, payload, asSse(sseManager));

    const rows = await db.query<{ count: number }>(
      "SELECT COUNT(*) as count FROM cached_patients WHERE hospital_id = ?",
      [hospitalId],
    );
    expect(rows[0].count).toBe(payload.patients.length);
  });

  it('CID is hashed with SHA-256 for labor patients', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    await processWebhookPayload(db, hospitalId, payload, asSse(sseManager));

    for (const p of payload.patients) {
      const expectedHash = cidHash(p.cid);
      const rows = await db.query<{ cid_hash: string }>(
        'SELECT cid_hash FROM cached_patients WHERE hospital_id = ? AND an = ?',
        [hospitalId, p.an],
      );
      expect(rows.length).toBeGreaterThan(0);
      expect(rows[0].cid_hash).toBe(expectedHash);
    }
  });

  it('labor fixture has exactly 1 active patient with expected values', () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    expect(payload.patients.length).toBe(1);
    expect(payload.mode).toBe('incremental');
    const p = payload.patients[0];
    expect(p.hn).toBe('006800004');
    expect(p.an).toBe('690000004');
    expect(p.age).toBe(30);
    expect(p.gravida).toBe(1);
    expect(p.ga_weeks).toBe(40);
    expect(p.height_cm).toBe(168);
    expect(p.weight_kg).toBe(87.0);
    expect(p.labor_status).toBe('ACTIVE');
    expect(p.anc_count).toBeNull();  // known gap: admit records don't carry ANC count
    expect(p.admit_date).toBe('2026-03-25T15:02:13+07:00');
  });

  it('labor patients with null anc_count are handled gracefully', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    const nullCountPatients = payload.patients.filter((p) => p.anc_count == null);
    // There should be at least one in the fixture
    expect(nullCountPatients.length).toBeGreaterThan(0);

    // Should not throw
    await expect(
      processWebhookPayload(db, hospitalId, payload, asSse(sseManager)),
    ).resolves.not.toThrow();
  });

  it('CPD score can be calculated from labor fixture data', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    // Import here to avoid circular issues at module level
    const { calculateCpdScore } = await import('@/services/cpd-score');

    for (const p of payload.patients) {
      const factors = {
        gravida: p.gravida ?? undefined,
        gaWeeks: p.ga_weeks ?? undefined,
        ancCount: p.anc_count ?? undefined,
        heightCm: p.height_cm ?? undefined,
        weightDiffKg: p.weight_diff_kg ?? undefined,
        fundalHeightCm: p.fundal_height_cm ?? undefined,
        usWeightG: p.us_weight_g ?? undefined,
        hematocritPct: p.hematocrit_pct ?? undefined,
      };
      // Should not throw even with partial data
      expect(() => calculateCpdScore(factors)).not.toThrow();
      const result = calculateCpdScore(factors);
      expect(typeof result.score).toBe('number');
      expect(['LOW', 'MEDIUM', 'HIGH']).toContain(result.riskLevel);
    }
  });

  it('hospital connection_status is set to ONLINE after labor processing', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    await processWebhookPayload(db, hospitalId, payload, asSse(sseManager));

    const rows = await db.query<{ connection_status: string }>(
      'SELECT connection_status FROM hospitals WHERE id = ?',
      [hospitalId],
    );
    expect(rows[0].connection_status).toBe('ONLINE');
  });

  it('SSE sync-complete event is broadcast', async () => {
    const payload = loadFixture<WebhookPayload>('labor-patients.json');
    await processWebhookPayload(db, hospitalId, payload, asSse(sseManager));

    const syncEvents = sseManager.getEventsByType('sync-complete');
    expect(syncEvents.length).toBeGreaterThan(0);
  });
});

// ─── Suite 4: Referral Processing Validation ───

describe('Suite 4: Referral Processing Validation', () => {
  let db: SqliteAdapter;
  let sseManager: MockSseManager;
  let fromHospitalId: string;
  let toHospitalId: string;

  beforeEach(async () => {
    db = new SqliteAdapter(':memory:');
    await SchemaSync.sync(db, ALL_TABLES, 'sqlite');
    await new SeedOrchestrator().run(db);
    sseManager = new MockSseManager();

    const createFixture = loadFixture<WebhookReferralCreatePayload>('referral-create.json');

    fromHospitalId = await getOrCreateHospital(db, createFixture.hospitalCode, 'รพ.ต้นทาง ทดสอบ', 'F1');
    await createApiKey(db, fromHospitalId, 'From Hospital Key');

    toHospitalId = await getOrCreateHospital(db, createFixture.toHospitalCode, 'รพ.ปลายทาง ทดสอบ', 'A_S');
    await createApiKey(db, toHospitalId, 'To Hospital Key');
  });

  afterEach(async () => {
    await db.close();
  });

  it('creates a referral record with status INITIATED', async () => {
    const payload = loadFixture<WebhookReferralCreatePayload>('referral-create.json');
    const result = await processReferralCreate(db, fromHospitalId, payload, asSse(sseManager));

    expect(result.referralId).toBe(payload.referralId);
    expect(result.status).toBe('INITIATED');

    const rows = await db.query<{ status: string; refer_number: string }>(
      'SELECT status, refer_number FROM cached_referrals WHERE from_hospital_id = ? AND refer_number = ?',
      [fromHospitalId, payload.referralId],
    );
    expect(rows.length).toBe(1);
    expect(rows[0].status).toBe('INITIATED');
    expect(rows[0].refer_number).toBe(payload.referralId);
  });

  it('compound key (hospitalCode + referralId) prevents duplicate on re-send', async () => {
    const payload = loadFixture<WebhookReferralCreatePayload>('referral-create.json');
    await processReferralCreate(db, fromHospitalId, payload, asSse(sseManager));
    await processReferralCreate(db, fromHospitalId, payload, asSse(sseManager));

    const rows = await db.query<{ count: number }>(
      'SELECT COUNT(*) as count FROM cached_referrals WHERE from_hospital_id = ? AND refer_number = ?',
      [fromHospitalId, payload.referralId],
    );
    expect(rows[0].count).toBe(1);
  });

  it('referral update changes status correctly', async () => {
    if (!fixtureExists('referral-update.json')) return;

    const createPayload = loadFixture<WebhookReferralCreatePayload>('referral-create.json');
    const updatePayload = loadFixture<WebhookReferralUpdatePayload>('referral-update.json');

    // Create referral first
    await processReferralCreate(db, fromHospitalId, createPayload, asSse(sseManager));

    // Now update — sent from the receiving hospital
    const result = await processReferralUpdate(db, toHospitalId, updatePayload, asSse(sseManager));
    expect(result.referralId).toBe(updatePayload.referralId);
    expect(result.status).toBe(updatePayload.status);

    const rows = await db.query<{ status: string }>(
      'SELECT status FROM cached_referrals WHERE from_hospital_id = ? AND refer_number = ?',
      [fromHospitalId, updatePayload.referralId],
    );
    expect(rows.length).toBe(1);
    expect(rows[0].status).toBe(updatePayload.status);
  });

  it('SSE referral_update event is broadcast on create', async () => {
    const payload = loadFixture<WebhookReferralCreatePayload>('referral-create.json');
    await processReferralCreate(db, fromHospitalId, payload, asSse(sseManager));

    const events = sseManager.getEventsByType('referral_update');
    expect(events.length).toBeGreaterThan(0);
  });

  it('cross-hospital CID matching works: patient from ANC matches in referral', async () => {
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    const referralFixture = loadFixture<WebhookReferralCreatePayload>('referral-create.json');

    // First insert ANC data
    await processAncWebhook(db, fromHospitalId, ancFixture, asSse(sseManager));

    // Now create referral — same CID should link to existing journey
    await processReferralCreate(db, fromHospitalId, referralFixture, asSse(sseManager));

    const cidHashValue = cidHash(referralFixture.cid);
    const rows = await db.query<{ journey_id: string | null }>(
      `SELECT journey_id FROM cached_referrals WHERE from_hospital_id = ? AND refer_number = ?`,
      [fromHospitalId, referralFixture.referralId],
    );
    expect(rows.length).toBe(1);
    // journey_id should be linked (not null) because ANC data was there first
    expect(rows[0].journey_id).not.toBeNull();

    // Verify it maps to the correct journey via CID hash
    const journeyRows = await db.query<{ id: string }>(
      'SELECT id FROM maternal_journeys WHERE cid_hash = ?',
      [cidHashValue],
    );
    expect(journeyRows.length).toBeGreaterThan(0);
    expect(rows[0].journey_id).toBe(journeyRows[0].id);
  });
});

// ─── Suite 5: Referral Check API Logic Validation ───

describe('Suite 5: Referral Check API Logic Validation', () => {
  let db: SqliteAdapter;
  let sseManager: MockSseManager;
  let hospitalId: string;

  beforeEach(async () => {
    db = new SqliteAdapter(':memory:');
    await SchemaSync.sync(db, ALL_TABLES, 'sqlite');
    await new SeedOrchestrator().run(db);
    sseManager = new MockSseManager();

    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    hospitalId = await getOrCreateHospital(db, ancFixture.hospitalCode, 'รพ.ทดสอบ Check', 'F1');
    await createApiKey(db, hospitalId, 'Check Test Key');
    // Seed ANC data
    await processAncWebhook(db, hospitalId, ancFixture, asSse(sseManager));
  });

  afterEach(async () => {
    await db.close();
  });

  it('referral-check fixture has 3 CIDs including known ANC patient and unknown CID', () => {
    const checkFixture = loadFixture<Array<{ cid: string }>>('referral-check.json');
    expect(checkFixture.length).toBe(3);
    // First is ANC patient, second is labor patient, third is unknown
    expect(checkFixture[0].cid).toBe('1770401294201');  // ANC patient 0
    expect(checkFixture[1].cid).toBe('0999991049501');  // Labor patient
    expect(checkFixture[2].cid).toBe('0000000000000');  // Unknown
  });

  it('patient with ANC data: CID hash lookup finds the journey', async () => {
    const checkFixture = loadFixture<Array<{ cid: string }>>('referral-check.json');
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');

    // The first check CID in the fixture should be one of the ANC patients
    const knownCids = ancFixture.patients.map((p) => p.cid);
    const knownCheckCid = checkFixture.find((c) => knownCids.includes(c.cid));
    if (!knownCheckCid) return; // Skip if fixture doesn't overlap

    const hashValue = cidHash(knownCheckCid.cid);
    const rows = await db.query<{ care_stage: string }>(
      'SELECT care_stage FROM maternal_journeys WHERE cid_hash = ?',
      [hashValue],
    );
    expect(rows.length).toBeGreaterThan(0);
    expect(rows[0].care_stage).toBe('PREGNANCY');
  });

  it('unknown CID "0000000000000" returns no journey', async () => {
    const hashValue = cidHash('0000000000000');
    const rows = await db.query<{ id: string }>(
      'SELECT id FROM maternal_journeys WHERE cid_hash = ?',
      [hashValue],
    );
    expect(rows.length).toBe(0);
  });

  it('unknown CID (not in ANC or labor) returns no journey', async () => {
    const checkFixture = loadFixture<Array<{ cid: string }>>('referral-check.json');
    const ancCids = loadFixture<WebhookAncPayload>('anc-patients.json').patients.map((p) => p.cid);
    const laborCids = loadFixture<WebhookPayload>('labor-patients.json').patients.map((p) => p.cid);
    const knownCids = new Set([...ancCids, ...laborCids]);

    const unknownCheck = checkFixture.find((c) => !knownCids.has(c.cid));
    if (!unknownCheck) return; // All fixture CIDs are known

    const hashValue = cidHash(unknownCheck.cid);
    const rows = await db.query<{ id: string }>(
      'SELECT id FROM maternal_journeys WHERE cid_hash = ?',
      [hashValue],
    );
    expect(rows.length).toBe(0);
  });

  it('referral check fixture CIDs are 13 digits', () => {
    const checkFixture = loadFixture<Array<{ cid: string }>>('referral-check.json');
    for (const [i, entry] of checkFixture.entries()) {
      expect(
        /^\d{13}$/.test(entry.cid),
        `referral-check[${i}].cid "${entry.cid}" must be 13 digits`,
      ).toBe(true);
    }
  });
});

