describe('Suite 6: Edge Case Validation from Real Fixture Data', () => {
  let db: SqliteAdapter;
  let sseManager: MockSseManager;
  let hospitalId: string;

  beforeEach(async () => {
    db = new SqliteAdapter(':memory:');
    await SchemaSync.sync(db, ALL_TABLES, 'sqlite');
    await new SeedOrchestrator().run(db);
    sseManager = new MockSseManager();

    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    hospitalId = await getOrCreateHospital(db, ancFixture.hospitalCode, 'รพ.ทดสอบ Edge Cases', 'F1');
    await createApiKey(db, hospitalId, 'Edge Case Test Key');
  });

  afterEach(async () => {
    await db.close();
  });

  it('ANC patients with lmp and edc present are processed without errors', async () => {
    // Real fixture: all 5 patients have lmp and edc set (community ANC has complete dates)
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    const withDates = ancFixture.patients.filter((p) => p.lmp != null && p.edc != null);
    expect(withDates.length).toBe(ancFixture.patients.length); // All have dates in real data

    await expect(
      processAncWebhook(db, hospitalId, ancFixture, asSse(sseManager)),
    ).resolves.not.toThrow();
  });

  it('patients with null visit fields (bp, fetalHr) are processed without errors', async () => {
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    const nullVisitFieldPatients = ancFixture.patients.filter((p) =>
      p.visits?.some(
        (v) => v.bpSystolic == null || v.bpDiastolic == null || v.fetalHr == null,
      ),
    );
    expect(nullVisitFieldPatients.length).toBeGreaterThan(0);

    await expect(
      processAncWebhook(db, hospitalId, ancFixture, asSse(sseManager)),
    ).resolves.not.toThrow();
  });

  it('Thai characters in patient names are stored and retrieved without corruption', async () => {
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    await processAncWebhook(db, hospitalId, ancFixture, asSse(sseManager));

    // All journeys were inserted — just verify count, not decrypted content
    const rows = await db.query<{ count: number }>(
      'SELECT COUNT(*) as count FROM maternal_journeys WHERE hospital_id = ?',
      [hospitalId],
    );
    // If Thai string caused corruption/error, rows would be 0
    expect(rows[0].count).toBe(ancFixture.patients.length);
  });

  it('labor patients with anc_count null do not cause CPD score errors', async () => {
    const laborFixture = loadFixture<WebhookPayload>('labor-patients.json');
    const now = new Date().toISOString();
    const laborHospitalId = uuidv4();
    await db.execute(
      `INSERT INTO hospitals (id, hcode, name, level, is_active, connection_status, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      [laborHospitalId, laborFixture.hospitalCode + '_L', 'รพ.Labor Edge', 'M1', 1, 'UNKNOWN', now, now],
    );
    await createApiKey(db, laborHospitalId, 'Labor Edge Key');

    await expect(
      processWebhookPayload(db, laborHospitalId, laborFixture, asSse(sseManager)),
    ).resolves.not.toThrow();
  });

  it('ANC visit dates span Aug 2024–Feb 2025 range (multi-month real data)', () => {
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    const allDates: Date[] = [];
    for (const p of ancFixture.patients) {
      for (const v of p.visits ?? []) {
        allDates.push(new Date(v.date));
      }
    }
    const earliest = new Date(Math.min(...allDates.map((d) => d.getTime())));
    const latest = new Date(Math.max(...allDates.map((d) => d.getTime())));
    // Earliest visit: 2024-07-30, Latest: 2025-02-25
    expect(earliest.getFullYear()).toBe(2024);
    expect(latest.getFullYear()).toBe(2025);
    expect(latest.getTime()).toBeGreaterThan(earliest.getTime());
  });

  it('visit numbers within each patient are in chronological order', () => {
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    for (const [i, p] of ancFixture.patients.entries()) {
      if (!p.visits || p.visits.length < 2) continue;
      for (let j = 1; j < p.visits.length; j++) {
        const prev = new Date(p.visits[j - 1].date);
        const curr = new Date(p.visits[j].date);
        expect(
          curr.getTime(),
          `patients[${i}] visits[${j}].date must be >= visits[${j - 1}].date`,
        ).toBeGreaterThanOrEqual(prev.getTime());
      }
    }
  });

  it('date formats in fixtures are consistent (YYYY-MM-DD or ISO 8601)', () => {
    const ancFixture = loadFixture<WebhookAncPayload>('anc-patients.json');
    const dateRe = /^\d{4}-\d{2}-\d{2}/; // YYYY-MM-DD prefix
    for (const p of ancFixture.patients) {
      expect(dateRe.test(p.birthday)).toBe(true);
      if (p.lmp) expect(dateRe.test(p.lmp)).toBe(true);
      if (p.edc) expect(dateRe.test(p.edc)).toBe(true);
      for (const v of p.visits ?? []) {
        expect(dateRe.test(v.date)).toBe(true);
      }
    }
    const laborFixture = loadFixture<WebhookPayload>('labor-patients.json');
    for (const p of laborFixture.patients) {
      // ISO 8601 with timezone — just ensure parseable
      expect(isNaN(new Date(p.admit_date).getTime())).toBe(false);
    }
  });
});
